{
  "name": "temporal-fetch-url",
  "version": "1.0.0",
  "description": "Temporal workflow that performs an HTTP GET via an activity",
  "main": "index.js",
  "scripts": {
    "build": "tsc --build",
    "start": "bash scripts/start.sh",
    "worker": "ts-node src/worker.ts",
    "client": "ts-node src/client.ts"
  },
  "dependencies": {
    "@temporalio/activity": "^1.11.7",
    "@temporalio/client": "^1.11.7",
    "@temporalio/worker": "^1.11.7",
    "@temporalio/workflow": "^1.11.7"
  },
  "devDependencies": {
    "ts-node": "^10.9.2",
    "typescript": "^5.4.5",
    "@types/node": "^20.14.0"
  }
}

/**
 * activities.ts
 *
 * Activities are the correct place for all I/O (network calls, file system, etc.)
 * because they run in a normal Node.js context and are retried by Temporal on failure.
 * The workflow code itself must remain deterministic and must never perform I/O directly.
 */

/**
 * Performs a real HTTP GET request to the given URL and returns the response body
 * as a plain string. Uses the global `fetch` available in Node 18+.
 */
export async function fetchData(url: string): Promise<string> {
  const response = await fetch(url, {
    headers: {
      // GitHub API requires a User-Agent header
      'User-Agent': 'temporal-fetch-url-workflow/1.0',
    },
  });

  if (!response.ok) {
    throw new Error(
      `HTTP request failed: ${response.status} ${response.statusText} for URL ${url}`
    );
  }

  return await response.text();
}

/**
 * workflows.ts
 *
 * Workflow code runs inside Temporal's deterministic sandbox.
 * It MUST NOT perform any I/O or use non-deterministic APIs directly.
 * All side-effects (HTTP calls, DB writes, etc.) must be delegated to Activities.
 *
 * The `proxyActivities` helper creates a type-safe proxy that, when called inside
 * a workflow, schedules an activity execution on a Worker rather than running
 * the function inline.
 */

import { proxyActivities } from '@temporalio/workflow';

// Import only the *type* of the activities module so that the workflow bundle
// never accidentally pulls in Node.js-only code (e.g. `fetch`, `fs`, etc.).
import type * as activities from './activities';

// Create a proxy for the activities. Temporal requires that every activity
// invocation has either `startToCloseTimeout` or `scheduleToCloseTimeout` set.
// 30 seconds is generous for a lightweight HTTP call.
const { fetchData } = proxyActivities<typeof activities>({
  startToCloseTimeout: '30 seconds',
  retry: {
    maximumAttempts: 3,
  },
});

/**
 * FetchUrlWorkflow — accepts a URL, delegates the HTTP GET to the `fetchData`
 * activity, and returns the response body string to the caller.
 *
 * The workflow is kept deliberately thin: its only job is orchestration.
 */
export async function FetchUrlWorkflow(url: string): Promise<string> {
  const result = await fetchData(url);
  return result;
}

/**
 * worker.ts
 *
 * Registers the Workflow and Activity implementations with Temporal Cloud and
 * begins polling the `fetch-url-ts` task queue.
 *
 * Connection options:
 *   - TEMPORAL_ADDRESS   — host:port of the Temporal Cloud gRPC endpoint
 *   - TEMPORAL_API_KEY   — Temporal Cloud API key (used in place of mTLS certs)
 *   - TEMPORAL_NAMESPACE — the target Temporal Cloud namespace
 */

import { Worker, NativeConnection } from '@temporalio/worker';
import * as activities from './activities';
import path from 'path';

const TASK_QUEUE = 'fetch-url-ts';

async function run(): Promise<void> {
  const address = process.env.TEMPORAL_ADDRESS;
  const apiKey = process.env.TEMPORAL_API_KEY;
  const namespace = process.env.TEMPORAL_NAMESPACE;

  if (!address) throw new Error('TEMPORAL_ADDRESS environment variable is required');
  if (!apiKey) throw new Error('TEMPORAL_API_KEY environment variable is required');
  if (!namespace) throw new Error('TEMPORAL_NAMESPACE environment variable is required');

  // NativeConnection is the Rust-backed gRPC connection used by the Worker.
  // `tls: true` enables TLS (required for Temporal Cloud).
  // The API key is passed as metadata that Temporal Cloud accepts in lieu of mTLS certificates.
  const connection = await NativeConnection.connect({
    address,
    tls: true,
    apiKey,
  });

  const worker = await Worker.create({
    connection,
    namespace,
    taskQueue: TASK_QUEUE,

    // `workflowsPath` points to the compiled (or ts-node interpreted) workflow
    // module. The Worker SDK automatically bundles it with webpack so that the
    // deterministic sandbox has no access to Node.js built-ins.
    workflowsPath: require.resolve('./workflows'),

    // The activities object maps activity type names to their implementations.
    // The SDK derives the activity type name from the exported function name,
    // so `fetchData` here becomes the "fetchData" activity type in Temporal.
    activities,
  });

  console.log(`[worker] Polling task queue "${TASK_QUEUE}" on namespace "${namespace}" ...`);

  // worker.run() resolves only when the worker is shut down (e.g. SIGINT/SIGTERM).
  await worker.run();
}

run().catch((err) => {
  console.error('[worker] Fatal error:', err);
  process.exit(1);
});

/**
 * client.ts
 *
 * Connects to Temporal Cloud, starts (or re-uses) a `FetchUrlWorkflow` execution,
 * waits for it to complete, and prints the activity result to stdout.
 *
 * Environment variables consumed:
 *   - TEMPORAL_ADDRESS   — host:port of the Temporal Cloud gRPC endpoint
 *   - TEMPORAL_API_KEY   — Temporal Cloud API key
 *   - TEMPORAL_NAMESPACE — target Temporal Cloud namespace
 *   - ZEALT_RUN_ID       — unique run identifier; incorporated into the Workflow ID
 *                          so that concurrent CI runs never collide.
 */

import { Client, Connection } from '@temporalio/client';
import { FetchUrlWorkflow } from './workflows';

const TASK_QUEUE = 'fetch-url-ts';
const TARGET_URL = 'https://api.github.com/zen';

async function run(): Promise<void> {
  const address = process.env.TEMPORAL_ADDRESS;
  const apiKey = process.env.TEMPORAL_API_KEY;
  const namespace = process.env.TEMPORAL_NAMESPACE;
  const runId = process.env.ZEALT_RUN_ID;

  if (!address) throw new Error('TEMPORAL_ADDRESS environment variable is required');
  if (!apiKey) throw new Error('TEMPORAL_API_KEY environment variable is required');
  if (!namespace) throw new Error('TEMPORAL_NAMESPACE environment variable is required');
  if (!runId) throw new Error('ZEALT_RUN_ID environment variable is required');

  // Connection.connect is the JS/gRPC connection used by the Client.
  // `tls: true` enables TLS; `apiKey` authenticates with Temporal Cloud.
  const connection = await Connection.connect({
    address,
    tls: true,
    apiKey,
  });

  const client = new Client({
    connection,
    namespace,
  });

  const workflowId = `fetch-wf-${runId}`;

  console.log(`[client] Starting workflow "${workflowId}" on task queue "${TASK_QUEUE}" ...`);
  console.log(`[client] Target URL: ${TARGET_URL}`);

  // `client.workflow.execute` starts the workflow and waits for its result in
  // a single call. It is equivalent to `start` followed by `handle.result()`.
  const result = await client.workflow.execute(FetchUrlWorkflow, {
    taskQueue: TASK_QUEUE,
    workflowId,
    args: [TARGET_URL],
  });

  // Print the activity result (the GitHub Zen API response body) to stdout.
  console.log(result);

  await connection.close();
}

run().catch((err) => {
  console.error('[client] Fatal error:', err);
  process.exit(1);
});
